import{_ as i,p as a,q as l,a1 as e}from"./framework-e0dd9823.js";const h={},r=e('<h1 id="第-五-单元总结" tabindex="-1"><a class="header-anchor" href="#第-五-单元总结" aria-hidden="true">#</a> 第 五 单元总结</h1><h2 id="欲しい-愿望" tabindex="-1"><a class="header-anchor" href="#欲しい-愿望" aria-hidden="true">#</a> 欲しい（愿望）</h2><ul><li>今、何がいちばん欲しいですか。</li><li>洋服がいちばん欲しいです。</li><li>何も欲しいくないです。</li></ul><h2 id="たい-意愿的助动词" tabindex="-1"><a class="header-anchor" href="#たい-意愿的助动词" aria-hidden="true">#</a> たい（意愿的助动词）</h2><ul><li>日曜日、何をしたいですか。</li><li>わたしは映画を見たいです。</li><li>何もしたくないです。</li></ul><h2 id="ませんか-建议" tabindex="-1"><a class="header-anchor" href="#ませんか-建议" aria-hidden="true">#</a> ませんか（建议）</h2><ul><li>一緒にお茶を飲みませんか。</li></ul><h2 id="ましょう-提议" tabindex="-1"><a class="header-anchor" href="#ましょう-提议" aria-hidden="true">#</a> ましょう（提议）</h2><ul><li>ちょっと、休みましょう</li></ul><h2 id="でも-无论···都···" tabindex="-1"><a class="header-anchor" href="#でも-无论···都···" aria-hidden="true">#</a> でも（无论···都···）</h2><ul><li>だれでもわかります。</li><li>いつでも電話をしてください。</li><li>何でもいいです。</li></ul><h2 id="形容词-名词连接动词-副词用法" tabindex="-1"><a class="header-anchor" href="#形容词-名词连接动词-副词用法" aria-hidden="true">#</a> 形容词，名词连接动词（副词用法）</h2><ul><li>形 1：词尾“い”变成“く”，例如“小さい” → “小さくなりました”；</li><li>形 2：直接在词尾加“に”，例如“きれい” → “きれいになります”；</li><li>名词：直接在词尾加“に”，例如“医者”　 → “医者になります”；</li></ul><h2 id="なります-します-变化" tabindex="-1"><a class="header-anchor" href="#なります-します-变化" aria-hidden="true">#</a> なります/します（变化）</h2><p>します（使···变成···）</p><ul><li>部屋を明るくします。</li><li>服をきれいにします。</li><li>森さんを医者にします。</li></ul><p>なります（···变成···）</p><ul><li>部屋は明るくなりました。</li><li>服はきれいになりました。</li><li>森さんは医者になりました。</li></ul><h2 id="ほうがいいです-选择-建议" tabindex="-1"><a class="header-anchor" href="#ほうがいいです-选择-建议" aria-hidden="true">#</a> ほうがいいです（选择，建议）</h2><ul><li><p>形 1 + ほうがいいです 部屋は広いほうがいいです。</p></li><li><p>形 2 + なほうがいいです ホテルは有名なほうがいいです。</p></li></ul><h2 id="ないでください-否定请求-命令" tabindex="-1"><a class="header-anchor" href="#ないでください-否定请求-命令" aria-hidden="true">#</a> ～ないでください（否定请求，命令）</h2><ul><li>部屋のかぎを忘れないでください。</li><li>ここでタバコを吸わないでください。</li></ul><h2 id="なければなりません-不得不-必选" tabindex="-1"><a class="header-anchor" href="#なければなりません-不得不-必选" aria-hidden="true">#</a> ～なければなりません（不得不，必选）</h2><ul><li>この薬は毎日飲まなければなりません。</li><li>あっ、９時ですね。もい帰らないと「いけません」。</li></ul><h2 id="なくてもいいです-没有必要做某事" tabindex="-1"><a class="header-anchor" href="#なくてもいいです-没有必要做某事" aria-hidden="true">#</a> ～なくてもいいです（没有必要做某事）</h2><ul><li>明日は残業しなくてもいいです。</li><li>今お金を払わなくてもいいです。</li></ul><h2 id="何度も-数量多" tabindex="-1"><a class="header-anchor" href="#何度も-数量多" aria-hidden="true">#</a> 何度も（数量多）</h2><ul><li>昨日李さんも何度も電話をかけました。</li><li>漫画が大好きですから、何冊も買いました。</li></ul><h2 id="动词基本型-ことができます-能力-许可" tabindex="-1"><a class="header-anchor" href="#动词基本型-ことができます-能力-许可" aria-hidden="true">#</a> 动词基本型 + ことができます（能力，许可）</h2><ul><li><p>森さんはピアノを弾くことができます。（能力）</p></li><li><p>ここで写真を撮ってもいいですか。</p><ul><li>いいえ、ここでは写真を撮ることができません。（许可）</li></ul></li></ul><h2 id="こと-形式名词" tabindex="-1"><a class="header-anchor" href="#こと-形式名词" aria-hidden="true">#</a> こと（形式名词）</h2><ul><li>わたしはの趣味は音楽を聞くことです。</li></ul><h2 id="疑问词-か-不确定" tabindex="-1"><a class="header-anchor" href="#疑问词-か-不确定" aria-hidden="true">#</a> 疑问词 + か（不确定）</h2><ul><li>部屋にだれかいますか。</li><li>さようなら。いつかまた会いましょう。</li></ul><h2 id="前に、-在···之前···" tabindex="-1"><a class="header-anchor" href="#前に、-在···之前···" aria-hidden="true">#</a> ～前に、～（在···之前···）</h2><ul><li>こちらへ来る前に電話をかけてください。</li><li>会議の前に、資料をコピーします。</li></ul>',36),d=[r];function n(u,t){return a(),l("div",null,d)}const s=i(h,[["render",n],["__file","unit20-2.html.vue"]]);export{s as default};
